insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('economics:2-4-price:match:80b95f74', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Transmission of preferences”?", "options": ["Everything produced is sold — nothing is left to buy or sell", "A rising price reducing demand for a scarce resource so it goes to those willing and able to pay", "Consumers sending information to producers about their wants through what they buy", "The rectangle price × quantity under the equilibrium point"]}'::jsonb, '{"answer": 2, "explain": "“Transmission of preferences” means: Consumers sending information to producers about their wants through what they buy"}'::jsonb),
('economics:2-4-price:match:e21bf8eb', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price”?", "options": ["How much someone personally values a product — subjective and different for each person", "A rising price reducing demand for a scarce resource so it goes to those willing and able to pay", "The price at which quantity demanded exactly equals quantity supplied", "The sum of money needed to pay for a product, determined by supply and demand"]}'::jsonb, '{"answer": 3, "explain": "“Price” means: The sum of money needed to pay for a product, determined by supply and demand"}'::jsonb),
('economics:2-4-price:match:595687fa', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Worth”?", "options": ["A rising price reducing demand for a scarce resource so it goes to those willing and able to pay", "The rectangle price × quantity under the equilibrium point", "The sum of money needed to pay for a product, determined by supply and demand", "How much someone personally values a product — subjective and different for each person"]}'::jsonb, '{"answer": 3, "explain": "“Worth” means: How much someone personally values a product — subjective and different for each person"}'::jsonb),
('economics:2-4-price:match:f6790982', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consumer sovereignty”?", "options": ["How much someone personally values a product — subjective and different for each person", "The idea that consumers steer production decisions through their purchasing choices", "Prices changing to show producers where resources are needed", "Everything produced is sold — nothing is left to buy or sell"]}'::jsonb, '{"answer": 1, "explain": "“Consumer sovereignty” means: The idea that consumers steer production decisions through their purchasing choices"}'::jsonb),
('economics:2-4-price:match:d483ce16', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Revenue on a diagram”?", "options": ["The quantity bought and sold when the market clears", "Consumers sending information to producers about their wants through what they buy", "Price below equilibrium: quantity demanded exceeds quantity supplied, so the price rises", "The rectangle price × quantity under the equilibrium point"]}'::jsonb, '{"answer": 3, "explain": "“Revenue on a diagram” means: The rectangle price × quantity under the equilibrium point"}'::jsonb),
('economics:2-5-competition:exam:3aac5b89', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q1", "question": "If an industry is a monopoly...", "options": ["new firms can easily enter the market", "there are losses being made", "there are many buyers and sellers", "there is a single producer in the market"], "hint": "The strict definition of a TRUE monopoly — how many producers?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1 1a)</h5>\n<p><strong>Answer: D — there is a single producer in the market</strong></p>\n<ul>\n<li>A true monopoly means one producer. Barriers to entry are HIGH (not A), and ''many buyers and sellers'' describes a competitive market.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:10082f39', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q2", "question": "An increase in the level of competition in the market is most likely to lead to...", "options": ["a higher price", "a lower price", "less consumer choice", "less supply to the market"], "hint": "More rivals means more supply and more pressure to win customers — which way do prices go?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1 1b)</h5>\n<p><strong>Answer: B — a lower price</strong></p>\n<ul>\n<li>More competition means more supply and firms undercutting each other — prices fall, and choice INCREASES (not C).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:36dd4f50', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q4", "question": "Which one of the following is true of a market economy?", "options": ["All resources are owned by the state", "Factors of production do not have a price", "Producers respond to changes in consumer demand", "There is no competition amongst producers"], "hint": "In a market economy, prices come from demand and supply with unrestricted competition — so what steers producers?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1 1b)</h5>\n<p><strong>Answer: C — Producers respond to changes in consumer demand</strong></p>\n<ul>\n<li>Consumer sovereignty: demand signals steer production. State ownership (A) describes a planned economy, and competition is central, not absent (D).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:9977e72e', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q5", "question": "In an oligopolistic market there is...", "options": ["a single producer", "competition between a few large producers", "easy entry into the market", "no advertising"], "hint": "Oligopoly = FEW LARGE firms. A single producer is a monopoly, and oligopolies famously advertise heavily.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1 1a)</h5>\n<p><strong>Answer: B — competition between a few large producers</strong></p>\n<ul>\n<li>The oligopoly signature: a few large firms, high barriers to entry, and plenty of (often non-price) competition including advertising.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:3f80a03e', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q7", "question": "What type of market is this most likely to be?", "options": ["Competitive", "Monopoly", "Oligopoly", "Specialist"], "caseStudy": "<p>The actions of one firm in a market has a considerable effect on other firms.</p>", "hint": "INTERDEPENDENCE — each firm watching and reacting to a few big rivals — is the signature of one structure. (Most real candidates wrongly picked ''competitive''.)", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — Oligopoly</strong></p>\n<ul>\n<li>With only a few large firms, each firm''s actions (a price cut, a big campaign) considerably affect the others — interdependence.</li>\n<li>In a competitive market each firm is too small to matter to the rest; a monopoly has no rivals at all.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Only a few candidates gave the correct answer C. The most popular response was A, showing a lack of understanding of competitive as against oligopolistic markets.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:36e1867b', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q8", "question": "What is most likely to happen to a firm which does not reduce its price? It will...", "options": ["continue to be successful if its demand is price elastic", "employ more economies of scale to gain customers", "improve its efficiency to find ways to reduce costs", "lose customers and may eventually go out of business"], "caseStudy": "<p>Price competition typically leads to firms in the market reducing their prices.</p>", "hint": "Everyone else just got cheaper and this firm didn''t respond. Where do its customers go?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — lose customers and may eventually go out of business</strong></p>\n<ul>\n<li>In a price war, a firm that stands still loses its customers to cheaper rivals — with price ELASTIC demand the loss would be even faster (so A is backwards).</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:0d55a662', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q12", "question": "A characteristic of a monopoly is that there is an absence of...", "options": ["competition", "economies of scale", "opportunity cost", "productivity"], "hint": "One producer, no rivals — what is missing from the market?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: A — competition</strong></p>\n<ul>\n<li>A single producer faces no rivalry. Monopolies often have LARGE economies of scale (B), and opportunity cost and productivity exist in every market.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Most candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:1e8e90cd', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q13", "question": "What would be the best advice for a new business entering the restaurant market?", "options": ["Cut the profits on its products", "Extend the range of its products", "Reduce its production costs", "Spend money on advertising"], "hint": "A brand-new restaurant''s biggest problem: nobody knows it exists. What fixes that at market entry?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — Spend money on advertising</strong></p>\n<ul>\n<li>At market entry, a new firm is unknown — advertising builds awareness and tempts customers to try it. Extending the range and cost-cutting come later in the life cycle.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Most candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:ec21bb0c', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q15", "question": "A market is an oligopoly if...", "options": ["each of the firms in the market has only a few customers", "each of the firms in the market makes many products", "most of the market is supplied by a small number of firms", "there is only one firm in the market"], "hint": "The five-firm rule: a SMALL NUMBER of firms supplying MOST of the market.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — most of the market is supplied by a small number of firms</strong></p>\n<ul>\n<li>The defining feature of oligopoly — a few large firms hold the majority of the market share. One firm only (D) is a monopoly.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:040fb5fa', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q16", "question": "Which of the following is a feature of a monopoly?", "options": ["An inability to supply the market", "Collusion between rivals", "High barriers to entry", "Low prices"], "hint": "What keeps a monopoly a monopoly? Something must stop new firms from coming in. (And collusion needs RIVALS — a monopoly has none.)", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — High barriers to entry</strong></p>\n<ul>\n<li>Barriers to entry (patents, scale, location) are what protect the single producer. Collusion (B) needs multiple firms; monopolies usually mean HIGHER prices (not D).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:032e40f4', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q18", "question": "In a competitive market...", "options": ["the government must control the price", "the item that is traded must be a good", "the item that is traded must be a service", "there must be many sellers"], "hint": "Competition needs rivals. Goods AND services can both be traded competitively, and the market — not the government — sets the price.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — there must be many sellers</strong></p>\n<ul>\n<li>Many sellers is the defining requirement. Competitive markets trade goods OR services, and prices come from market forces, not government control.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:780839de', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q19", "question": "In which of the following markets is there a monopoly?", "options": ["There are many buyers and many sellers of a good", "There are many buyers and one seller of a service", "There is one buyer and many sellers of a good", "There is one buyer and many sellers of a service"], "hint": "Monopoly is about the SELLING side: ONE seller, however many buyers.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — There are many buyers and one seller of a service</strong></p>\n<ul>\n<li>Monopoly = a single SELLER. One buyer facing many sellers (C, D) is the reverse situation (a monopsony — not on this course).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:5c638a59', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q20", "question": "An oligopoly differs from a competitive market because...", "options": ["a competitive market has larger firms than an oligopoly", "a competitive market has lower barriers to entry than an oligopoly", "firms in an oligopoly do not differentiate their products", "firms in an oligopoly only compete on price"], "hint": "Think entry: how easy is it to open a market stall versus launch a fifth national supermarket chain?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — a competitive market has lower barriers to entry than an oligopoly</strong></p>\n<ul>\n<li>Easy entry keeps competitive markets crowded; oligopolies protect themselves with high barriers. Oligopolists DO differentiate and often avoid price competition (C, D backwards).</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option B as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:9b81a68d', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q21", "question": "Which of the following is the most likely result of increased competition within a market?", "options": ["High barriers to entry", "High production costs", "Increased profits", "Lower prices"], "hint": "More rivals fighting for the same customers — what happens to the price tags?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — Lower prices</strong></p>\n<ul>\n<li>Firms undercut each other to win customers — prices fall and profits are squeezed (so not C).</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:6d2d3716', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q23", "question": "The prices of branded goods, such as Heinz baked beans, are usually higher than a supermarket''s own label. This is likely to be due to...", "options": ["higher advertising costs", "higher productivity", "lower average costs", "lower profit margins"], "hint": "What does a national brand spend millions on that an own-label product doesn''t — and has to recoup through its price?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — higher advertising costs</strong></p>\n<ul>\n<li>Brands are built with heavy advertising, and those costs feed into the price — the classic example of competition costs pushing prices UP.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Most candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:7e4e3e7a', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q24", "question": "Firms need to survive in a market. Which of the following is an example of a suitable method to survive?", "options": ["Encourage existing customers to return", "Enter into competition with consumers", "Provide an external economy of scale", "Reduce total supply"], "hint": "Survival is about keeping revenue coming in — and the cheapest customers to win are the ones you already have.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — Encourage existing customers to return</strong></p>\n<ul>\n<li>Customer loyalty sustains revenue. Firms compete with other FIRMS, not consumers (B), and external economies of scale come from outside the firm (C).</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Most candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:exam:5971fabe', 'economics', 'economics:2-5-competition', '2.5 Competition', 'exam', 'mcq', 1, '{"num": "Q26", "question": "For someone living in the village wanting to buy bread, the shop is a...", "options": ["competitor", "monopolist", "oligopolist", "specialist"], "caseStudy": "<p>A village is over 10 miles away from the nearest two towns. The village shop sells bread. For someone living in the village wanting to buy bread, the shop is a...</p>", "hint": "LOCATION creates market power — with the nearest alternatives 10 miles away, how much choice does a villager really have?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — monopolist</strong></p>\n<ul>\n<li>For bread-buying villagers, the shop is the only realistic seller — a local monopoly created by location, one of the classic sources of monopoly power.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option B as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-5-competition:mcq:2f8db495', 'economics', 'economics:2-5-competition', '2.5 Competition', 'mcq', 'mcq', 1, '{"question": "Which of the following best defines competition?", "options": ["One firm controlling a market", "Rivalry between firms selling similar goods to the same group of consumers", "Consumers bargaining with each other", "The government setting prices"]}'::jsonb, '{"answer": 1, "explain": "Competition needs more than one firm chasing the same customers — the rivalry is what forces prices down and quality up."}'::jsonb),
('economics:2-5-competition:mcq:2b9cbadd', 'economics', 'economics:2-5-competition', '2.5 Competition', 'mcq', 'mcq', 1, '{"question": "A firm with over 25% market share is said to have...", "options": ["Monopoly power", "Perfect competition", "An oligopoly", "A true monopoly"]}'::jsonb, '{"answer": 0, "explain": "Monopoly POWER starts at 25% share (Tesco ~27%). A TRUE monopoly means literally one seller — much rarer."}'::jsonb),
('economics:2-5-competition:mcq:dc28ccb8', 'economics', 'economics:2-5-competition', '2.5 Competition', 'mcq', 'mcq', 1, '{"question": "The five largest firms in a market together control 62% of it. This market is best described as...", "options": ["A duopoly", "Perfectly competitive", "A true monopoly", "An oligopoly"]}'::jsonb, '{"answer": 3, "explain": "The working rule: five-firm concentration of 50% or more = oligopoly. The UK cinema and supermarket markets are classic examples."}'::jsonb),
('economics:2-5-competition:mcq:b403635c', 'economics', 'economics:2-5-competition', '2.5 Competition', 'mcq', 'mcq', 1, '{"question": "Which market structure is generally considered the MOST efficient?", "options": ["A monopoly", "A cartel", "An oligopoly", "A competitive market"]}'::jsonb, '{"answer": 3, "explain": "Many firms competing forces efficiency and low prices. The spectrum runs competitive (most) → oligopoly → monopoly (least efficient)."}'::jsonb),
('economics:2-5-competition:mcq:3afcf658', 'economics', 'economics:2-5-competition', '2.5 Competition', 'mcq', 'mcq', 1, '{"question": "Firms in an industry secretly agree to keep their prices high. This is called...", "options": ["Collusion — and it is illegal in the UK", "A loss leader", "Non-price competition", "Consumer sovereignty"]}'::jsonb, '{"answer": 0, "explain": "Collusion cheats consumers of the benefits of competition — the CMA takes action against cartels."}'::jsonb),
('economics:2-5-competition:mcq:fd34248c', 'economics', 'economics:2-5-competition', '2.5 Competition', 'mcq', 'mcq', 1, '{"question": "A pharmaceutical firm patents a new medicine. For the life of the patent the firm is...", "options": ["A price taker", "A perfectly competitive firm", "A monopolist in that medicine", "An oligopolist"]}'::jsonb, '{"answer": 2, "explain": "Intellectual property (patents/copyright) is one of the classic sources of monopoly — sole selling rights for a period."}'::jsonb),
('economics:2-5-competition:mcq:e0fba939', 'economics', 'economics:2-5-competition', '2.5 Competition', 'mcq', 'mcq', 1, '{"question": "Which is an example of NON-price competition?", "options": ["A 20% discount", "Building a strong brand through advertising", "A two-for-one offer", "A loss leader"]}'::jsonb, '{"answer": 1, "explain": "Non-price competition works on the product, promotion, service and brand — common in oligopolies. The other three all compete on price."}'::jsonb),
('economics:2-5-competition:mcq:7f633d7a', 'economics', 'economics:2-5-competition', '2.5 Competition', 'mcq', 'mcq', 1, '{"question": "A monopolist raises its price far above the competitive level. What still limits how high it can go?", "options": ["Its competitors'' prices", "The firm''s supply curve", "Nothing — monopolists set any price", "Demand — raising prices too far cuts sales"]}'::jsonb, '{"answer": 3, "explain": "Even a monopolist faces a downward-sloping demand curve — price too high and customers stop buying (or regulators step in)."}'::jsonb),
('economics:2-5-competition:mcq:4172b7c9', 'economics', 'economics:2-5-competition', '2.5 Competition', 'mcq', 'mcq', 1, '{"question": "Which body investigates mergers and cartels in the UK?", "options": ["The Competition and Markets Authority (CMA)", "The World Trade Organization", "HM Revenue and Customs", "The Bank of England"]}'::jsonb, '{"answer": 0, "explain": "The CMA promotes competition for consumers'' benefit — it blocked the Asda–Sainsbury''s merger and investigates anti-competitive behaviour."}'::jsonb),
('economics:2-5-competition:mcq:a9a09391', 'economics', 'economics:2-5-competition', '2.5 Competition', 'mcq', 'mcq', 1, '{"question": "Increased competition is most likely to benefit consumers through...", "options": ["Lower prices, better quality and wider choice", "Higher barriers to entry", "Higher prices and less choice", "More collusion"]}'::jsonb, '{"answer": 0, "explain": "The classic consumer gains — though be ready to evaluate: aggressive advertising and corner-cutting on quality are the other side."}'::jsonb),
('economics:2-5-competition:tf:83708599', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tf', 'tf', 1, '{"question": "A monopoly means there is an absence of competition."}'::jsonb, '{"answer": true, "explain": "With a single producer there is no rivalry — ''an absence of competition'' is a real exam MCQ answer for the characteristic of monopoly."}'::jsonb),
('economics:2-5-competition:tf:18bc21af', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tf', 'tf', 1, '{"question": "A firm needs 100% market share to have monopoly power."}'::jsonb, '{"answer": false, "explain": "Monopoly POWER starts at just over 25% market share — Tesco''s ~27% of UK groceries counts. A TRUE monopoly (one seller) is a stricter idea."}'::jsonb),
('economics:2-5-competition:tf:2fca0158', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tf', 'tf', 1, '{"question": "In an oligopoly, the actions of one firm have a considerable effect on the other firms."}'::jsonb, '{"answer": true, "explain": "Interdependence is the hallmark of oligopoly — with only a few large rivals, each watches and reacts to the others. A real MCQ most candidates got wrong!"}'::jsonb),
('economics:2-5-competition:tf:aa23218d', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tf', 'tf', 1, '{"question": "An oligopoly has lower barriers to entry than a competitive market."}'::jsonb, '{"answer": false, "explain": "It''s the reverse: competitive markets have LOW barriers (easy entry); oligopolies protect themselves with high barriers like massive advertising budgets."}'::jsonb),
('economics:2-5-competition:tf:00f8a5b0', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tf', 'tf', 1, '{"question": "Increased competition in a market most likely leads to lower prices."}'::jsonb, '{"answer": true, "explain": "More rivals = more supply and more consumer choice, pushing prices down — though advertising and R&D costs can limit the fall."}'::jsonb),
('economics:2-5-competition:tf:6bcb64ce', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tf', 'tf', 1, '{"question": "A firm that refuses to respond in a price war will keep all its customers."}'::jsonb, '{"answer": false, "explain": "It will lose customers to cheaper rivals and may eventually go out of business — the real exam MCQ answer."}'::jsonb),
('economics:2-5-competition:tf:d650ab56', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tf', 'tf', 1, '{"question": "The only shop in a remote village can act as a local monopolist."}'::jsonb, '{"answer": true, "explain": "Location creates monopoly power — villagers have no realistic alternative, so the shop can charge more than one facing town competition."}'::jsonb),
('economics:2-5-competition:tf:43cfb39a', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tf', 'tf', 1, '{"question": "Competition is always good for consumers."}'::jsonb, '{"answer": false, "explain": "Mostly good (prices, quality, choice) — but aggressive advertising, corner-cutting on quality and hidden charges are genuine downsides. Evaluate both sides."}'::jsonb),
('economics:2-5-competition:learn:7e6db687', 'economics', 'economics:2-5-competition', '2.5 Competition', 'learn', 'mcq', 1, '{"readingTitle": "Competition — what it is and why producers compete", "reading": "<p><strong>Competition is the rivalry between firms that operate in the same market</strong> — more than one firm trying to sell similar goods to the same group of consumers.</p>\n<h4>WHY producers compete (a real 2-marker: \"State two reasons\")</h4>\n<ul>\n<li>To <strong>enter</strong> a market, and then to <strong>survive</strong> in it.</li>\n<li>To increase <strong>revenue, sales, reputation</strong> and recognition.</li>\n<li>To <strong>make a profit</strong> — the ultimate goal.</li>\n<li>To increase <strong>market share</strong>, gain customers and build loyalty.</li>\n<li>Even to <strong>force competitors out</strong> and become a monopoly.</li>\n</ul>\n<h4>HOW firms compete</h4>\n<ul>\n<li><strong>On price</strong> — discounts, two-for-one offers, giveaways, and <strong>loss leaders</strong>: products priced at little or no profit to pull customers into the store, who then buy other things.</li>\n<li><strong>On quality</strong> — charging more but winning on the product (Waitrose, M&amp;S).</li>\n<li><strong>On innovation</strong> — constantly developing new products (Apple).</li>\n<li><strong>On customer service</strong> — how high-end restaurants and hotels stand apart.</li>\n<li><strong>Through advertising</strong> — building brand recognition and loyalty.</li>\n</ul>\n<h4>Competition changes with the life cycle</h4>\n<ul>\n<li><strong>Market entry</strong> — an unknown firm uses giveaways and low introductory prices to tempt customers to try it.</li>\n<li><strong>Growth</strong> — expand the product range to reach more customers (supermarkets moving into banking, mobiles, petrol and clothing).</li>\n<li><strong>Maturity</strong> — keep innovating to avoid decline (McDonald''s endlessly refreshing its menu).</li>\n</ul>", "question": "A supermarket sells bread at a loss to pull shoppers into the store, where they buy other products. The bread is...", "options": ["A merit good", "A loss leader", "An oligopoly", "A monopoly good"]}'::jsonb, '{"answer": 1, "explain": "A loss leader is deliberately priced at little or no profit to attract customers whose OTHER purchases make the money."}'::jsonb),
('economics:2-5-competition:learn:7e640f5d', 'economics', 'economics:2-5-competition', '2.5 Competition', 'learn', 'mcq', 1, '{"readingTitle": "How competition affects price", "reading": "<p>The headline: more competition usually means <strong>lower prices</strong> — but the full story earns the higher marks.</p>\n<h4>The market view</h4>\n<ul>\n<li>Competition increases when <strong>new firms enter</strong> the market or existing firms grow. More sellers means more supplied at every price — market supply shifts RIGHT, so the equilibrium price falls and quantity rises.</li>\n<li>PED sets the extent: with <strong>elastic demand</strong>, prices need fall only a little to sell much more; with <strong>inelastic demand</strong>, prices must fall further to shift the same extra output.</li>\n</ul>\n<h4>The single-firm view (usually scores better in 6-markers!)</h4>\n<ul>\n<li>For one firm — like a café facing new rivals — competition means consumers have more <strong>substitutes</strong>, so the DEMAND for that firm''s products shifts LEFT. The firm must cut the prices it can charge, and sells less.</li>\n<li>How much depends on the firm''s quality, customer loyalty and the PED of its products.</li>\n</ul>\n<h4>Why competition doesn''t ALWAYS cut prices</h4>\n<ul>\n<li>Competing costs money: heavy <strong>advertising</strong> spend and expensive <strong>R&amp;D</strong> may need to be recouped through HIGHER prices.</li>\n<li>Non-price competition (better products, service, branding) can let a firm hold its prices up despite new rivals.</li>\n</ul>\n<h4>What happens to a firm that won''t respond?</h4>\n<ul>\n<li>In a price war, a firm that does not reduce its price (or improve its offer) loses customers and may eventually go out of business — a real exam MCQ.</li>\n</ul>", "question": "New cafés open near Nina and Leo''s café. Seen from THEIR café, what happens?", "options": ["Demand for their products shifts right", "Demand for their products shifts left, forcing their prices down", "Nothing — they are a monopoly", "Their supply curve shifts left"]}'::jsonb, '{"answer": 1, "explain": "More substitutes pull customers away — the single firm''s demand shifts left. The real examiner report said candidates using this firm-level view were generally more successful."}'::jsonb),
('economics:2-5-competition:learn:eb2508ea', 'economics', 'economics:2-5-competition', '2.5 Competition', 'learn', 'mcq', 1, '{"readingTitle": "The spectrum: competitive markets, oligopoly, monopoly", "reading": "<p>Market structure is the number of firms in an industry and how they behave. Learn the definitions WITH their numbers:</p>\n<h4>Competitive market</h4>\n<ul>\n<li>A <strong>large number of (mostly small) firms</strong>, few barriers to entry, similar products, and <strong>little control over price</strong> — firms are price TAKERS; market forces set the price. Considered the MOST efficient structure.</li>\n</ul>\n<h4>Oligopoly</h4>\n<ul>\n<li>A <strong>small number of large firms supply most of the market</strong> — the working definition: the five largest firms control <strong>50% or more</strong>. Example: UK cinemas (Cineworld, Odeon, Vue hold over 75%).</li>\n<li>Barriers to entry (like heavy advertising) exist; firms often compete on NON-price factors; each firm''s actions considerably affect the others — <strong>interdependence</strong>.</li>\n<li><strong>Collusion</strong> — agreeing to keep prices artificially high — is illegal.</li>\n</ul>\n<h4>Monopoly</h4>\n<ul>\n<li><strong>True monopoly</strong>: a single producer in the market. <strong>Monopoly power</strong>: any firm with over <strong>25% market share</strong> (Tesco ~27% of groceries; BT ~33% of broadband; Microsoft 75%+ of desktop operating systems).</li>\n<li>Features: <strong>high barriers to entry</strong>, lack of substitutes, more control over price (price MAKERS — though demand still limits them), an absence of competition, and generally the LEAST efficient structure.</li>\n<li>Why they arise: <strong>patents and copyrights</strong>, extreme <strong>economies of scale</strong>, <strong>location</strong> (the only shop in a remote village is a local monopolist — a real MCQ!), or historically <strong>legal monopolies</strong> (Royal Mail letters).</li>\n</ul>\n<p><strong>Efficiency spectrum:</strong> competitive markets (most efficient) → oligopoly → monopoly (least efficient) — though monopolies with big cost advantages sometimes choose LOW prices to sell more.</p>", "question": "A village shop over 10 miles from the nearest towns sells bread. For villagers, the shop is a...", "options": ["Monopolist", "Specialist", "Competitor", "Oligopolist"]}'::jsonb, '{"answer": 0, "explain": "Location creates a local monopoly — villagers have no realistic alternative, so the shop can charge more. This exact scenario is a real exam MCQ."}'::jsonb),
('economics:2-5-competition:learn:426a98bf', 'economics', 'economics:2-5-competition', '2.5 Competition', 'learn', 'mcq', 1, '{"readingTitle": "The economic impact on producers and consumers — and the CMA", "reading": "<p>The topic''s signature Evaluate question: is competition good for consumers, and what does it do to producers?</p>\n<h4>Producers</h4>\n<ul>\n<li>✔ Pushed to become <strong>efficient</strong> (computerisation, mechanisation → productivity) and to <strong>innovate</strong> — innovators can charge high prices before rivals catch up, then reinvest the profits.</li>\n<li>✘ Firms that <strong>fail to adapt</strong> lose market share and can be driven out of business; competition squeezes prices and profits; needed inputs (skilled workers, equipment at auction) get bid up in price.</li>\n</ul>\n<h4>Consumers</h4>\n<ul>\n<li>✔ <strong>Lower prices</strong> (more disposable income left over), <strong>better quality</strong>, <strong>wider choice</strong>, more innovation — a better quality of life overall.</li>\n<li>✘ But: <strong>aggressive advertising</strong> can push people to buy things they don''t need or can''t afford; firms may <strong>cut corners on quality</strong> to keep prices low; harmful additives/pesticides may creep in; low headline prices can hide extra charges.</li>\n</ul>\n<h4>The Competition and Markets Authority (CMA)</h4>\n<ul>\n<li>The UK''s competition regulator. It <strong>investigates mergers</strong> (it blocked the Asda–Sainsbury''s merger to protect supermarket competition), <strong>investigates whole markets</strong> (e.g. retail banking), acts against <strong>cartels and collusion</strong>, and protects consumers from <strong>unfair trading practices</strong> (misleading messages, aggressive selling).</li>\n</ul>\n<h4>Evaluation lines that earn Level 3</h4>\n<ul>\n<li>The benefits depend on HOW firms compete — genuine value vs marketing spin.</li>\n<li>Smaller firms may lack the economies of scale of big rivals, limiting how far prices fall.</li>\n<li>Very intense price competition can squeeze quality or wages.</li>\n</ul>", "question": "Why did the CMA block the proposed Asda–Sainsbury''s merger?", "options": ["The firms were too small", "It would reduce competition in the supermarket industry and harm consumers", "Supermarkets are a legal monopoly", "It would create too much competition"]}'::jsonb, '{"answer": 1, "explain": "The CMA''s job is to protect competition for consumers'' benefit — fewer big supermarkets would mean higher prices and less choice."}'::jsonb),
('economics:2-5-competition:misc:74f90548', 'economics', 'economics:2-5-competition', '2.5 Competition', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"An oligopoly is when there are many firms and lots of competition.\"</p><p><strong>✅ The correct idea:</strong> The real examiner report said the oligopoly definition ''was not answered well'' — many candidates wrote exactly this. An oligopoly is a market where a SMALL NUMBER OF LARGE FIRMS control the majority of the market share (rule of thumb: the five largest firms hold 50% or more). And precision doubles your marks: OCR''s ''need for precision'' note showed that ''an oligopoly is a few large firms, but a competitive market has smaller firms'' scored 1, while ''a few LARGE firms versus MANY SMALL firms'' scored 2. Say both the number AND the size, for both structures.</p>", "question": "Which sentence earns the full 2 marks for distinguishing an oligopoly from a competitive market?", "options": ["An oligopoly is a few large firms; a competitive market is many small firms", "An oligopoly is one big firm", "An oligopoly means lots of competition", "An oligopoly has smaller firms than a competitive market"]}'::jsonb, '{"answer": 0, "explain": "Number AND size for BOTH markets — the real mark scheme''s worked example of 1 mark vs 2 marks."}'::jsonb),
('economics:2-5-competition:misc:994f3c6f', 'economics', 'economics:2-5-competition', '2.5 Competition', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Monopoly means literally one firm with 100% of the market.\"</p><p><strong>✅ The correct idea:</strong> A TRUE monopoly is a single producer — but in exams the more useful idea is MONOPOLY POWER: any firm with over 25% market share (Tesco ~27% of groceries, BT ~33% of broadband). Monopolies also arise without giant firms: patents give sole selling rights, and LOCATION creates local monopolies — the only shop in a village 10 miles from town is a monopolist for its residents (a real MCQ). Know all the routes to monopoly: intellectual property, extreme economies of scale, location, and (historically) legal monopoly.</p>", "question": "Tesco has about 27% of the UK grocery market. Tesco has...", "options": ["Monopoly power (over 25% share)", "A true monopoly", "No market power", "An illegal cartel"]}'::jsonb, '{"answer": 0, "explain": "Over 25% = monopoly power, even with many rivals. True monopoly needs a single seller."}'::jsonb),
('economics:2-5-competition:misc:323820e3', 'economics', 'economics:2-5-competition', '2.5 Competition', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"More competition always means lower prices for consumers.\"</p><p><strong>✅ The correct idea:</strong> Usually — but not always, and the ''not always'' is where Level 3 lives. Competing costs money: firms that fight back with heavy ADVERTISING or expensive R&D may need to recoup those costs through higher prices, and innovative firms can charge premium prices for products rivals can''t match. Non-price competition (quality, service, brand) lets firms hold prices up. The real café mark scheme explicitly credited ''increased marketing can push prices up'' and ''an innovative café may be able to charge higher prices''.</p>", "question": "Which is a reason competition might NOT cut prices?", "options": ["Supply always falls when firms compete", "Competition is illegal", "Consumers prefer high prices", "Firms need to recoup heavy advertising and R&D spending"]}'::jsonb, '{"answer": 3, "explain": "The costs of competing can offset the downward pressure — the classic evaluative twist on this topic."}'::jsonb),
('economics:2-5-competition:misc:c7c047f7', 'economics', 'economics:2-5-competition', '2.5 Competition', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Competition between football clubs means winning cups and trophies.\"</p><p><strong>✅ The correct idea:</strong> In ECONOMICS, competition means rivalry in MARKETS — and the real Muncaster United question punished candidates who wrote about trophies. The club competes in the market for PLAYERS (where competition bids up transfer prices, hurting a small club), the market for SUPPORTERS (revenue), and the market for finance. Better answers analysed how the competitive transfer market makes good players expensive and how failing to compete there costs promotion, supporters and revenue. Translate any unusual context back into markets, buyers and sellers.</p>", "question": "\"Evaluate the economic impact of competition on Muncaster United.\" The competition to analyse is in the market for...", "options": ["Players and supporters — bidding up transfer prices and revenue rivalry", "Cups and trophies", "Stadium names", "Referees"]}'::jsonb, '{"answer": 0, "explain": "The examiner report: weaker answers treated competition as winning trophies. The economics is in the transfer and supporter markets."}'::jsonb),
('economics:2-5-competition:misc:00d8c778', 'economics', 'economics:2-5-competition', '2.5 Competition', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Reasons firms compete? Profit. Market share. Revenue.\"</p><p><strong>✅ The correct idea:</strong> One-word answers score NOTHING on ''State two reasons why businesses compete'' — the mark scheme says ''no marks for just stating: market share, revenue, profit, etc.'' Add the verb and the point: ''TO MAKE a profit'', ''TO INCREASE market share and gain customers'', ''TO SURVIVE in the market'', ''TO ENTER a market''. It costs three extra words and it is the difference between 0 and 2.</p>", "question": "Which answer would score on ''State two reasons why businesses compete''?", "options": ["Profit. Revenue.", "To make a profit; to increase market share and gain customers", "Money", "Competition"]}'::jsonb, '{"answer": 1, "explain": "Full (if short) statements with a verb — bare nouns were explicitly given no marks in the real mark scheme."}'::jsonb),
('economics:2-5-competition:misc:63d22fa4', 'economics', 'economics:2-5-competition', '2.5 Competition', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Evaluate the extent to which competition benefits consumers — I''ll write about how it helps the business.\"</p><p><strong>✅ The correct idea:</strong> Stakeholder discipline again: on the real Letusprovide question, ''references to Letusprovide benefitting could not be credited'' — the application marks needed the CONSUMER. And on the evaluation, ''the emphasis was on the EXTENT'', so answers ending with a summary like ''consumers gain from competition'' were capped at one evaluation mark. The winning shape: consumer benefits (prices, quality, choice) → consumer costs (persuasive advertising, corner-cutting, hidden charges) → a judgement about HOW FAR the benefits win and what that depends on.</p>", "question": "On ''Evaluate the extent to which competition is beneficial for consumers'', points about the FIRM benefitting were...", "options": ["Worth double", "Given full marks", "Required", "Not credited — the question is about consumers"]}'::jsonb, '{"answer": 3, "explain": "The examiner report is explicit. Match every point to the stakeholder named in the question."}'::jsonb),
('economics:2-5-competition:tips:6b84feb7', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tips', 'mcq', 1, '{"readingTitle": "definitions — Market structure definitions: numbers + precision", "reading": "<p>The 2-markers on this paper are definition-led. Learn them with their numbers:</p>\n<ul>\n<li><strong>Oligopoly</strong> — a small number of large firms control the majority of the market (five largest ≥ 50%); barriers to entry; possible collusion; often non-price competition.</li>\n<li><strong>Oligopoly vs competitive market</strong> — a FEW LARGE firms vs MANY SMALL firms; price setters vs price takers; high vs low barriers to entry.</li>\n<li><strong>Monopoly characteristics</strong> — single producer / 25%+ share, high barriers to entry, absence of competition, more control over price.</li>\n</ul>\n<h4>How real answers scored</h4>\n<p>❌ <strong>0–1 mark:</strong> \"An oligopoly means many firms and lots of competition\" — the definition reversed.</p>\n<p>⚠️ <strong>1 mark:</strong> \"An oligopoly is made up of a few large firms, but a competitive market consists of smaller firms\" — the sizes without the numbers.</p>\n<p>✅ <strong>2 marks:</strong> \"An oligopoly is made up of a few large firms, but a competitive market consists of many small firms.\"</p>\n<p>Also watch exclusions: on the OPEC question, repeating the extract''s phrase ''different outcomes for prices'' earned nothing.</p>", "question": "On the OPEC oligopoly question, quoting the extract''s phrase ''different outcomes for prices'' scored...", "options": ["2 marks", "Bonus credit", "Nothing — it was stated in the extract", "1 mark"]}'::jsonb, '{"answer": 2, "explain": "The mark scheme: ''No reward for a general reference to different outcomes for prices as that is stated in the extract.'' Add your own economics."}'::jsonb),
('economics:2-5-competition:tips:0043532b', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tips', 'mcq', 1, '{"readingTitle": "sixmarker — The competition-on-prices 6-marker: pick the firm-level diagram", "reading": "<p>\"Analyse the effect of increased competition from new cafés on the prices Nina and Leo can charge\" was the most consistently answered 6-marker on its paper — and the examiners revealed the winning route:</p>\n<ul>\n<li>Two valid diagrams: the whole MARKET with supply shifting right (price falls), or the single FIRM with demand shifting left (their price falls). <strong>Candidates using the firm''s-eye view were generally more successful.</strong></li>\n<li><strong>Keep the exact focus</strong> — ''the prices Nina and Leo can charge''. Answers drifting into general consequences of competition stalled at Level 2.</li>\n<li>Use the extract''s elasticity: demand for their products is price inelastic, which limits how far their price falls.</li>\n<li>Add the twist: <strong>non-price competition</strong> (quality, service, refurbishment) could let them defend their prices.</li>\n<li>And as always: refer to the diagram in your writing — drawn-but-unused diagrams restricted marks.</li>\n</ul>", "question": "For ''competition''s effect on the prices ONE firm can charge'', the diagram examiners rated more successful shows...", "options": ["A wage-setting diagram", "The firm''s supply curve shifting left", "The firm''s demand curve shifting left", "A production possibility frontier"]}'::jsonb, '{"answer": 2, "explain": "New rivals = more substitutes = demand for THIS firm''s products shifts left, forcing its price down. The market-supply-right diagram is also valid."}'::jsonb),
('economics:2-5-competition:tips:7a0a23ae', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tips', 'mcq', 1, '{"readingTitle": "calculation — The calculations: interest savings, profit/loss, price per unit", "reading": "<p>Three calculation types on this paper:</p>\n<ul>\n<li><strong>Interest saving</strong> — 6% of £10,000 (£600) vs 5% (£500) → saving £100. Or the shortcut: 1% of £10,000.</li>\n<li><strong>Profit or loss</strong> — total revenue − total cost: £1,024,000 − (650,000 + 175,000 + 225,000 + 50,000 = £1,100,000) = <strong>−£76,000</strong>. You MUST say ''loss'' or show the minus sign — a bare ''£76,000'' with no indication drops a mark.</li>\n<li><strong>Price per unit</strong> — total revenue ÷ output: £500,000 ÷ 200 = <strong>£2,500</strong>. Here the correct answer ALONE was only 1 mark — the £ sign and working were required for both.</li>\n</ul>\n<h4>Universal rules</h4>\n<ul>\n<li>Show working — the Own Figure Rule rescues 1 mark after a slip, but only if the method is visible.</li>\n<li>Read which figures the question wants: the profit calculation needed ALL FOUR cost lines added first.</li>\n</ul>", "question": "Air Madeira: revenue £1,024,000, total costs £1,100,000. Writing ''£76,000'' with no minus sign or ''loss'' scores...", "options": ["1 mark of the 2", "Nothing", "Both marks", "3 marks"]}'::jsonb, '{"answer": 0, "explain": "The mark scheme: an answer of £76000 ''with no indication whether it is a profit or a loss'' = 1 mark. Label it a loss."}'::jsonb),
('economics:2-5-competition:tips:bc5ed091', 'economics', 'economics:2-5-competition', '2.5 Competition', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Evaluate questions: stakeholder + the extra requirement", "reading": "<p>Four Evaluate 6-markers on this paper, each with its own frame:</p>\n<ul>\n<li><strong>''The extent to which competition benefits CONSUMERS''</strong> — consumer points only (firm benefits ''could not be credited''), and the judgement must weigh HOW FAR, not just conclude ''consumers gain'' (capped at 1 evaluation mark).</li>\n<li><strong>''The importance to Air Madeira of making a PROFIT''</strong> — internal finance, growth, attracting investors, survival... balanced against tolerating a short-term loss while a new route builds.</li>\n<li><strong>''The economic impact of competition on Muncaster United''</strong> — competition in the PLAYER market bids up prices against a small club; not trophies.</li>\n<li><strong>''The effects of increased competition on the CONSUMERS of SSA''</strong> — remember the video-notes trick: SSA''s consumers are AIRLINES (businesses), so frame effects around their costs and what they buy.</li>\n</ul>\n<h4>The pattern</h4>\n<p>Name the stakeholder → analyse for THAT stakeholder using the extract''s numbers → weigh both sides → judge within the question''s frame (extent / importance / impact), adding something new.</p>", "question": "\"Evaluate the effects of increased competition on the consumers of SSA Ltd''s products.\" SSA sells computer equipment for aeroplanes — so its consumers are...", "options": ["Households buying laptops", "Businesses (airlines) — frame effects around their costs and purchases", "The government", "SSA''s workers"]}'::jsonb, '{"answer": 1, "explain": "When the ''consumers'' are other businesses, analyse THEIR profits and costs — the trick flagged in the topic''s video notes."}'::jsonb),
('economics:2-5-competition:fib:6a3f1d90', 'economics', 'economics:2-5-competition', '2.5 Competition', 'fib', 'fib', 2, '{"question": "Competition is the ___B1___ between firms operating in the same market. Firms compete to enter a market, survive, gain customers and make a ___B2___.", "blankOptions": {"B1": ["prices", "rivalry", "efficient", "power"], "B2": ["profit", "small", "entry", "collusion"]}}'::jsonb, '{"blanks": {"B1": "rivalry", "B2": "profit"}}'::jsonb),
('economics:2-5-competition:fib:c5d8e3f9', 'economics', 'economics:2-5-competition', '2.5 Competition', 'fib', 'fib', 2, '{"question": "A true monopoly has only ___B1___ seller, while a firm with over 25% market share has monopoly ___B2___.", "blankOptions": {"B1": ["entry", "one", "left", "many"], "B2": ["power", "small", "leader", "rivalry"]}}'::jsonb, '{"blanks": {"B1": "one", "B2": "power"}}'::jsonb),
('economics:2-5-competition:fib:22ce1c03', 'economics', 'economics:2-5-competition', '2.5 Competition', 'fib', 'fib', 2, '{"question": "In an oligopoly, a ___B1___ number of large firms supply most of the market, and there are barriers to ___B2___ such as heavy advertising.", "blankOptions": {"B1": ["rivalry", "small", "efficient", "fall"], "B2": ["entry", "profit", "fall", "collusion"]}}'::jsonb, '{"blanks": {"B1": "small", "B2": "entry"}}'::jsonb),
('economics:2-5-competition:fib:e5823e5f', 'economics', 'economics:2-5-competition', '2.5 Competition', 'fib', 'fib', 2, '{"question": "Increased competition usually shifts market supply right, so prices ___B1___ — but for a single firm, new rivals shift the demand for its products to the ___B2___.", "blankOptions": {"B1": ["prices", "fall", "efficient", "many"], "B2": ["rise", "one", "left", "many"]}}'::jsonb, '{"blanks": {"B1": "fall", "B2": "left"}}'::jsonb),
('economics:2-5-competition:fib:615a4716', 'economics', 'economics:2-5-competition', '2.5 Competition', 'fib', 'fib', 2, '{"question": "Firms agreeing to keep prices artificially high is called ___B1___ and is illegal. A product sold at little or no profit to attract customers is a loss ___B2___.", "blankOptions": {"B1": ["collusion", "one", "profit", "left"], "B2": ["leader", "prices", "efficient", "entry"]}}'::jsonb, '{"blanks": {"B1": "collusion", "B2": "leader"}}'::jsonb),
('economics:2-5-competition:fib:0360610a', 'economics', 'economics:2-5-competition', '2.5 Competition', 'fib', 'fib', 2, '{"question": "Competitive markets are the most ___B1___ market structure; monopolies are generally the least. Advertising and R&D costs explain why competition does not always cut ___B2___.", "blankOptions": {"B1": ["profit", "left", "one", "efficient"], "B2": ["left", "collusion", "leader", "prices"]}}'::jsonb, '{"blanks": {"B1": "efficient", "B2": "prices"}}'::jsonb),
('economics:2-5-competition:match:684313b6', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Competition”?", "options": ["Rivalry between firms operating in the same market for the same customers", "Firms agreeing together to keep prices artificially high — illegal in the UK", "A small number of large firms supply most of the market (five-firm share of 50%+)", "Competing through the product, promotion, service and brand instead of price"]}'::jsonb, '{"answer": 0, "explain": "“Competition” means: Rivalry between firms operating in the same market for the same customers"}'::jsonb),
('economics:2-5-competition:match:814af92d', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market structure”?", "options": ["A large number of mostly small firms, few barriers to entry, little control over price", "The number of firms in an industry and the way those businesses behave", "Any firm with over 25% market share", "Competing through the product, promotion, service and brand instead of price"]}'::jsonb, '{"answer": 1, "explain": "“Market structure” means: The number of firms in an industry and the way those businesses behave"}'::jsonb),
('economics:2-5-competition:match:5e66eb19', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Competitive market”?", "options": ["The number of firms in an industry and the way those businesses behave", "A large number of mostly small firms, few barriers to entry, little control over price", "A firm with enough market power to influence the price it charges", "Competing through the product, promotion, service and brand instead of price"]}'::jsonb, '{"answer": 1, "explain": "“Competitive market” means: A large number of mostly small firms, few barriers to entry, little control over price"}'::jsonb),
('economics:2-5-competition:match:215b40b8', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Oligopoly”?", "options": ["A small number of large firms supply most of the market (five-firm share of 50%+)", "Competing through the product, promotion, service and brand instead of price", "The UK regulator that investigates mergers, cartels and unfair trading", "The number of firms in an industry and the way those businesses behave"]}'::jsonb, '{"answer": 0, "explain": "“Oligopoly” means: A small number of large firms supply most of the market (five-firm share of 50%+)"}'::jsonb),
('economics:2-5-competition:match:1c8682de', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “True monopoly”?", "options": ["A large number of mostly small firms, few barriers to entry, little control over price", "A market with only one producer or seller of a product", "A firm that must accept the market price — typical of competitive markets", "Rivalry between firms operating in the same market for the same customers"]}'::jsonb, '{"answer": 1, "explain": "“True monopoly” means: A market with only one producer or seller of a product"}'::jsonb),
('economics:2-5-competition:match:e58f1114', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Monopoly power”?", "options": ["Obstacles that make it hard for new firms to enter a market, like heavy advertising or patents", "Any firm with over 25% market share", "The number of firms in an industry and the way those businesses behave", "A market with only one producer or seller of a product"]}'::jsonb, '{"answer": 1, "explain": "“Monopoly power” means: Any firm with over 25% market share"}'::jsonb),
('economics:2-5-competition:match:15d12699', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Barriers to entry”?", "options": ["A small number of large firms supply most of the market (five-firm share of 50%+)", "Competing through the product, promotion, service and brand instead of price", "Obstacles that make it hard for new firms to enter a market, like heavy advertising or patents", "A market with only one producer or seller of a product"]}'::jsonb, '{"answer": 2, "explain": "“Barriers to entry” means: Obstacles that make it hard for new firms to enter a market, like heavy advertising or patents"}'::jsonb),
('economics:2-5-competition:match:8ecf7d53', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price taker”?", "options": ["A firm that must accept the market price — typical of competitive markets", "A firm with enough market power to influence the price it charges", "Obstacles that make it hard for new firms to enter a market, like heavy advertising or patents", "A market with only one producer or seller of a product"]}'::jsonb, '{"answer": 0, "explain": "“Price taker” means: A firm that must accept the market price — typical of competitive markets"}'::jsonb),
('economics:2-5-competition:match:ce619268', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price maker”?", "options": ["Obstacles that make it hard for new firms to enter a market, like heavy advertising or patents", "A firm that must accept the market price — typical of competitive markets", "A firm with enough market power to influence the price it charges", "A small number of large firms supply most of the market (five-firm share of 50%+)"]}'::jsonb, '{"answer": 2, "explain": "“Price maker” means: A firm with enough market power to influence the price it charges"}'::jsonb),
('economics:2-5-competition:match:5fae340c', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Loss leader”?", "options": ["A product priced at little or no profit to attract customers who then buy other things", "The number of firms in an industry and the way those businesses behave", "The UK regulator that investigates mergers, cartels and unfair trading", "Any firm with over 25% market share"]}'::jsonb, '{"answer": 0, "explain": "“Loss leader” means: A product priced at little or no profit to attract customers who then buy other things"}'::jsonb),
('economics:2-5-competition:match:ca03fd07', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Collusion”?", "options": ["The number of firms in an industry and the way those businesses behave", "A product priced at little or no profit to attract customers who then buy other things", "Firms agreeing together to keep prices artificially high — illegal in the UK", "A large number of mostly small firms, few barriers to entry, little control over price"]}'::jsonb, '{"answer": 2, "explain": "“Collusion” means: Firms agreeing together to keep prices artificially high — illegal in the UK"}'::jsonb),
('economics:2-5-competition:match:0f000d32', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Non-price competition”?", "options": ["Competing through the product, promotion, service and brand instead of price", "A product priced at little or no profit to attract customers who then buy other things", "A firm that must accept the market price — typical of competitive markets", "The UK regulator that investigates mergers, cartels and unfair trading"]}'::jsonb, '{"answer": 0, "explain": "“Non-price competition” means: Competing through the product, promotion, service and brand instead of price"}'::jsonb),
('economics:2-5-competition:match:d2e90384', 'economics', 'economics:2-5-competition', '2.5 Competition', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Competition and Markets Authority”?", "options": ["The number of firms in an industry and the way those businesses behave", "The UK regulator that investigates mergers, cartels and unfair trading", "A large number of mostly small firms, few barriers to entry, little control over price", "Rivalry between firms operating in the same market for the same customers"]}'::jsonb, '{"answer": 1, "explain": "“Competition and Markets Authority” means: The UK regulator that investigates mergers, cartels and unfair trading"}'::jsonb),
('economics:2-6-production:exam:35aaa94d', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q4", "question": "Plumbers who work for themselves are examples of individuals as...", "options": ["competitors", "consumers", "employers", "producers"], "hint": "They MAKE a service (plumbing) — which economic role is that?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — producers</strong></p>\n<ul>\n<li>Self-employed individuals producing a service are producers — one of the three types of producer (individuals, firms, government).</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Most candidates gave D as the correct response. Some had not read the question carefully enough and gave answer C.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:87a36744', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q5", "question": "What is NOT likely to result from an increase in production in an industry?", "options": ["An increase in profits", "An increase in the output of goods", "Greater environmental sustainability", "Increased economies of scale"], "hint": "Three follow naturally from producing more. One usually gets WORSE when output rises — think resources used.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — Greater environmental sustainability</strong></p>\n<ul>\n<li>More production means more resources used and more waste — the environment usually suffers, not benefits. Profits, output and economies of scale all tend to rise with production.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Most of the candidates gave C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:07aad6da', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q6", "question": "Which of these statements is NOT true?", "options": ["Any firm may become an oligopoly", "Governments produce services which the private sector will not", "Households make decisions based on opportunity cost", "Individuals cannot be producers of goods and services"], "hint": "Think of the self-employed plumber — CAN individuals be producers?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — Individuals cannot be producers of goods and services</strong></p>\n<ul>\n<li>This is FALSE (which makes it the answer): individuals like self-employed tradespeople are producers. The other three statements are true.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>The correct response was Option D. Incorrect responses ranged across the other three options and indicated some gaps in candidates'' knowledge and understanding.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:f85d465e', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q7", "question": "What is the most likely outcome?", "options": ["Charlie has decreased the costs of production more than Gabi", "Charlie has increased the economies of scale more than Gabi", "Gabi has decreased the average revenue of their business compared to Charlie''s", "Gabi has increased the competitiveness of their business compared to Charlie''s"], "caseStudy": "<p>Charlie has increased the production of their business by 10%. Gabi has increased the productivity of their business by 10%. The prices of their products have not changed.</p>", "hint": "PRODUCTIVITY (Gabi) means more output from the same inputs → lower average costs → more competitive. Production (Charlie) just means more output.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — Gabi has increased the competitiveness of their business compared to Charlie''s</strong></p>\n<ul>\n<li>Raising PRODUCTIVITY cuts average costs (same inputs, more output), making Gabi more competitive. Raising PRODUCTION alone doesn''t guarantee lower unit costs.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>The correct response is Option D. Incorrect responses indicated a misunderstanding of the difference between production and productivity and the possible implications of changes in both.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:be1181f4', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q9", "question": "If output increases from 1 to 4, what is the change in the firm''s AVERAGE cost?", "options": ["+ £32", "+ £14", "− £14", "− £10"], "caseStudy": "<table style=\"width:100%;max-width:300px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Output</th><th style=\"padding:6px;\">Total cost (£)</th></tr>\n<tr><td style=\"padding:6px;\">1</td><td>24</td></tr>\n<tr><td style=\"padding:6px;\">2</td><td>36</td></tr>\n<tr><td style=\"padding:6px;\">3</td><td>48</td></tr>\n<tr><td style=\"padding:6px;\">4</td><td>56</td></tr>\n</table>", "hint": "AVERAGE cost = TC ÷ output. At 1 unit it''s £24; at 4 units it''s £56 ÷ 4. The +£32 trap is the change in TOTAL cost.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: D — −£10</strong></p>\n<ul>\n<li>AC at output 1 = £24. AC at output 4 = £56 ÷ 4 = £14. Change = £14 − £24 = −£10.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>The correct response was Option D. However, many candidates gave Option A as they had not noticed the word ''average'' within the stem of this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:2e88f8fa', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Which statement is correct?", "options": ["Average costs always decrease as output increases", "Average costs always increase as output increases", "Average costs start to rise when 300 units are produced", "Average costs start to rise when 400 units are produced"], "caseStudy": "<table style=\"width:100%;max-width:320px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Quantity</th><th style=\"padding:6px;\">Total Cost (£)</th></tr>\n<tr><td style=\"padding:6px;\">100</td><td>1000</td></tr>\n<tr><td style=\"padding:6px;\">200</td><td>1800</td></tr>\n<tr><td style=\"padding:6px;\">300</td><td>2550</td></tr>\n<tr><td style=\"padding:6px;\">400</td><td>3600</td></tr>\n</table>", "hint": "Work out AC at each row: £10, £9, £8.50, £9. AC reaches its minimum at 300 — from that point it starts to rise.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: C — Average costs start to rise when 300 units are produced</strong></p>\n<ul>\n<li>AC: 100 → £10; 200 → £9; 300 → £8.50; 400 → £9. Average cost bottoms out at 300 units — beyond that point it starts rising (diseconomies setting in).</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Many candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:7df77695', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q12", "question": "The diagram shows the relationship between output and total revenue of a firm. Which statement is correct?", "options": ["Total revenue increases at all levels of output", "Total revenue increases from 0 to T and then falls", "Total revenue increases from 0 to U and then falls", "Total revenue increases from 0 to V and then falls"], "caseStudy": "<img src=\"/images/economics/2-6-tr-output-diagram-extracted.png\" alt=\"Diagram from the OCR exam paper: total revenue rising steeply from the origin, flattening between T and U, peaking at U, then falling to V, with output points S, T, U and V marked\" style=\"display:block;width:100%;max-width:440px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "Find the PEAK of the TR curve — it keeps rising (even if more slowly) until point U, then turns down.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: C — Total revenue increases from 0 to U and then falls</strong></p>\n<ul>\n<li>TR still rises between T and U (just more slowly); the peak is at U. After U the curve turns down.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Many candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:e0a0432e', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q13", "question": "As a business increases in size it is able to employ more specialist staff. Which economy of scale does this describe?", "options": ["Increased dimensions", "Managerial", "Marketing", "Risk-bearing"], "hint": "Specialist staff running each department — production, finance, sales — is the definition of one particular economy.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — Managerial</strong></p>\n<ul>\n<li>Managerial economies: a bigger firm can afford specialist managers for each department, maximising output — something a small self-employed builder handling everything alone cannot do.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Many candidates gave Option B as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:85755417', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q16", "question": "How does the production of a service differ from the production of a good?", "options": ["It is intangible", "No capital is required", "No labour is required", "Specialisation is not possible"], "hint": "Services still need labour, capital and specialisation — the one true difference is that you can''t touch them.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — It is intangible</strong></p>\n<ul>\n<li>Services have no physical form — that''s the defining difference. They still require capital, labour and specialisation, so B, C and D are false.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:5aff8313', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q17", "question": "Which of the following is an example of an EXTERNAL economy of scale?", "options": ["Bulk-buying", "Financial", "Location", "Risk-bearing"], "hint": "Three are internal (they come from the firm''s own growth). One comes from WHERE the firm is — outside its control, benefiting every firm nearby.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — Location</strong></p>\n<ul>\n<li>Location advantages (clustering, local infrastructure, nearby suppliers) are external — available to all firms in the area regardless of size. Bulk-buying, financial and risk-bearing economies are internal.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:167ca238', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q18", "question": "The table shows a firm''s total costs. Which of the following statements is correct?", "options": ["The firm gains economies of scale as output increases from 10 to 20 units", "The firm gains economies of scale as output increases from 20 to 30 units", "The firm gains economies of scale as output increases from 30 to 40 units", "There are no economies of scale over any range of output"], "caseStudy": "<table style=\"width:100%;max-width:380px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Output per week (units)</th><th style=\"padding:6px;\">Total costs (£)</th></tr>\n<tr><td style=\"padding:6px;\">10</td><td>100</td></tr>\n<tr><td style=\"padding:6px;\">20</td><td>160</td></tr>\n<tr><td style=\"padding:6px;\">30</td><td>240</td></tr>\n<tr><td style=\"padding:6px;\">40</td><td>400</td></tr>\n</table>", "hint": "Work out AVERAGE cost at each output: £10, £8, £8, £10. Where does it FALL?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: A — economies of scale from 10 to 20 units</strong></p>\n<ul>\n<li>AC: 10 → £10; 20 → £8; 30 → £8; 40 → £10. Average cost only FALLS between 10 and 20 units — that''s where the economies of scale are.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:fcc6f9d7', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q19", "question": "An increase in productivity will ALWAYS lead to...", "options": ["A fall in average costs", "A fall in total costs", "An increase in profit", "An increase in specialisation"], "hint": "More output per unit of input means each unit costs less — guaranteed. Profit and total costs depend on other things.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — A fall in average costs</strong></p>\n<ul>\n<li>By definition: same inputs, more output → lower cost per unit. Total costs may still rise with output, and profit depends on revenue too — only average costs fall ''always''.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:e7575794', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q22", "question": "The table shows the total costs of a firm. It sells its output for £5 each. How many units of output per day does the firm need to sell to maximise profits?", "options": ["2", "3", "4", "5"], "caseStudy": "<table style=\"width:100%;max-width:380px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Units of output per day</th><th style=\"padding:6px;\">Total costs (£)</th></tr>\n<tr><td style=\"padding:6px;\">2</td><td>3</td></tr>\n<tr><td style=\"padding:6px;\">3</td><td>5</td></tr>\n<tr><td style=\"padding:6px;\">4</td><td>9</td></tr>\n<tr><td style=\"padding:6px;\">5</td><td>15</td></tr>\n</table>", "hint": "Profit at each row = (£5 × units) − total cost: £7, £10, £11, £10. Which output gives the biggest?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: C — 4 units</strong></p>\n<ul>\n<li>Profit: 2 units → £10 − £3 = £7; 3 → £15 − £5 = £10; 4 → £20 − £9 = £11; 5 → £25 − £15 = £10. Maximum profit (£11) is at 4 units.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:67def8d0', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q23", "question": "Which of the following is an example of an economy of scale?", "options": ["Bulk-buying of materials", "Increased raw material costs", "Sustainable production", "Unemployment"], "hint": "Which one CUTS the cost per unit as a firm grows bigger?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — Bulk-buying of materials</strong></p>\n<ul>\n<li>Purchasing economies — bigger orders, better prices per unit. The classic example (though remember there are eight more types!).</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:8efb5356', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q24", "question": "Which of the following statements MUST be true?", "options": ["Its profits will decrease", "Its profits will increase", "Its revenue will decrease", "Its revenue will increase"], "caseStudy": "<p>A firm raises the price of its products from £10 to £11. Its sales fall from 100 to 90 units per day.</p>", "hint": "Work out TR before (£10 × 100) and after (£11 × 90). Profit can''t be judged — we don''t know the costs.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: C — Its revenue will decrease</strong></p>\n<ul>\n<li>TR falls from £10 × 100 = £1,000 to £11 × 90 = £990. Profit depends on costs too, which we aren''t told — so only the revenue statement MUST be true.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:29e45de3', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q25", "question": "The table shows a firm''s output and its average costs of production. It can sell output at £3 per unit. What is the maximum possible profit?", "options": ["0", "£20", "£40", "£60"], "caseStudy": "<table style=\"width:100%;max-width:420px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Units of output</th><th style=\"padding:6px;\">Average costs of production (£)</th></tr>\n<tr><td style=\"padding:6px;\">10</td><td>3</td></tr>\n<tr><td style=\"padding:6px;\">20</td><td>2</td></tr>\n<tr><td style=\"padding:6px;\">30</td><td>1</td></tr>\n<tr><td style=\"padding:6px;\">40</td><td>2</td></tr>\n</table>", "hint": "Profit per unit = £3 − AC. At 30 units that''s £2 per unit × 30 units. Check the other rows too.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: D — £60</strong></p>\n<ul>\n<li>Profit = (price − AC) × output: 10 → £0; 20 → £20; 30 → (£3−£1)×30 = £60; 40 → £40. The maximum is £60 at 30 units.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A majority of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:0ec15437', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q26", "question": "The diagram shows the relationship between output and the total costs of production, TC. Which of these statements about the diagram MUST be true?", "options": ["Average costs rise when output rises", "Profits increase with an increase in output", "The firm still has costs to pay even if it produces nothing", "Total revenue will be increasing"], "caseStudy": "<img src=\"/images/economics/2-6-tc-diagram-extracted.png\" alt=\"Diagram from the OCR exam paper: total costs of production TC rising in a straight line as output rises, starting above zero on the cost axis\" style=\"display:block;width:100%;max-width:420px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "Look where the TC line STARTS — above zero on the cost axis, at zero output. What kind of costs are those?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — The firm still has costs to pay even if it produces nothing</strong></p>\n<ul>\n<li>The TC line cuts the cost axis above zero — those are the FIXED costs, paid whatever the output. The diagram says nothing about revenue or profits.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A majority of candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:81982f9d', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q29", "question": "Calculate the firm''s total costs in 2019.", "options": ["£6900", "£18 000", "£18 900", "£20 700"], "caseStudy": "<table style=\"width:100%;max-width:340px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\"></th><th style=\"padding:6px;\">2018</th></tr>\n<tr><td style=\"padding:6px;\">Fixed cost</td><td>£12 000</td></tr>\n<tr><td style=\"padding:6px;\">Variable cost</td><td>£20 per unit</td></tr>\n<tr><td style=\"padding:6px;\">Output</td><td>300 units</td></tr>\n</table>\n<p>In 2019, variable costs increased by 15% but fixed costs and output did not change.</p>", "hint": "New variable cost = £20 × 1.15 = £23 per unit × 300 units, then ADD the unchanged £12,000 fixed costs.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: C — £18,900</strong></p>\n<ul>\n<li>VC in 2019 = £20 × 1.15 = £23 per unit; £23 × 300 = £6,900. TC = £12,000 fixed + £6,900 variable = £18,900.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:638a1083', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q30", "question": "The table shows the total revenue of a firm. If output increases from 1 to 4, what is the change in the firm''s AVERAGE revenue?", "options": ["+ £28", "+ £18", "− £10", "− £3"], "caseStudy": "<table style=\"width:100%;max-width:320px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Total output</th><th style=\"padding:6px;\">Total revenue (£)</th></tr>\n<tr><td style=\"padding:6px;\">1</td><td>10</td></tr>\n<tr><td style=\"padding:6px;\">2</td><td>18</td></tr>\n<tr><td style=\"padding:6px;\">3</td><td>24</td></tr>\n<tr><td style=\"padding:6px;\">4</td><td>28</td></tr>\n</table>", "hint": "AR = TR ÷ output. At 1 unit it''s £10; at 4 units it''s £28 ÷ 4 = £7.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: D — −£3</strong></p>\n<ul>\n<li>AR at 1 = £10; AR at 4 = £28 ÷ 4 = £7. Change = £7 − £10 = −£3. Another ''average'' word trap!</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Many candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:95ce187b', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q33", "question": "The table shows the cost of insurance for a car, depending on the age of the driver. Which of the following statements is correct?", "options": ["A 20-year-old driver pays twice as much as a 50-year-old driver", "A 30-year-old driver pays £500 less than a 20-year-old driver", "The smallest change in insurance payment is between the ages of 30 and 40", "The largest percentage change in insurance payment is between the ages of 40 and 50"], "caseStudy": "<table style=\"width:100%;max-width:340px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Age of driver</th><th style=\"padding:6px;\">Cost of insurance (£)</th></tr>\n<tr><td style=\"padding:6px;\">20</td><td>1302</td></tr>\n<tr><td style=\"padding:6px;\">30</td><td>756</td></tr>\n<tr><td style=\"padding:6px;\">40</td><td>662</td></tr>\n<tr><td style=\"padding:6px;\">50</td><td>534</td></tr>\n</table>", "hint": "Check each gap: 20→30 = £546, 30→40 = £94, 40→50 = £128. Which is smallest?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: C — The smallest change is between the ages of 30 and 40</strong></p>\n<ul>\n<li>The falls are £546, £94 and £128 — the 30-to-40 gap (£94) is the smallest. (A 20-year-old pays MORE than twice a 50-year-old, and the 20→30 fall is £546, not £500.)</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:exam:d819c726', 'economics', 'economics:2-6-production', '2.6 Production', 'exam', 'mcq', 1, '{"num": "Q34", "question": "As a result of its growth, a business can now afford to advertise on local radio. This is an example of which economy of scale?", "options": ["Financial", "Increased dimensions", "Marketing", "Purchasing"], "hint": "Advertising the business can now afford = which of the nine types?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — Marketing</strong></p>\n<ul>\n<li>Marketing economies: a bigger firm can afford expensive advertising (radio, TV) and spread the cost over far more sales.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-6-production:mcq:ca6d8f55', 'economics', 'economics:2-6-production', '2.6 Production', 'mcq', 'mcq', 1, '{"question": "Which is the best definition of ''production''?", "options": ["Output per worker", "The number of workers employed", "The profit a firm makes", "The total output of goods and services in a given time period"]}'::jsonb, '{"answer": 3, "explain": "Production = total output + a time period. Output per worker is PRODUCTIVITY — keep the two apart."}'::jsonb),
('economics:2-6-production:mcq:2c338fa4', 'economics', 'economics:2-6-production', '2.6 Production', 'mcq', 'mcq', 1, '{"question": "Which is the best definition of ''productivity''?", "options": ["The number of goods sold", "Total output of a country", "Output per unit of input, such as output per worker", "Total revenue divided by price"]}'::jsonb, '{"answer": 2, "explain": "Productivity measures EFFICIENCY — how much output each unit of input produces. Answers that only mention output score nothing on the real 2-marker."}'::jsonb),
('economics:2-6-production:mcq:4726e605', 'economics', 'economics:2-6-production', '2.6 Production', 'mcq', 'mcq', 1, '{"question": "A pizza shop pays rent whether it sells any pizzas or not. The rent is a...", "options": ["Marginal revenue", "Variable cost", "Fixed cost", "Total cost"]}'::jsonb, '{"answer": 2, "explain": "Fixed costs don''t vary with output. The ingredients are the variable costs — they rise with every pizza made."}'::jsonb),
('economics:2-6-production:mcq:f26bce6c', 'economics', 'economics:2-6-production', '2.6 Production', 'mcq', 'mcq', 1, '{"question": "A firm has fixed costs of £300 and variable costs of £6 per unit. Its total cost at 200 units is...", "options": ["£1,500", "£300", "£900", "£1,200"]}'::jsonb, '{"answer": 0, "explain": "TC = FC + VC = £300 + (£6 × 200 = £1,200) = £1,500. Never forget to add the fixed costs — the most common real-exam calculation slip."}'::jsonb),
('economics:2-6-production:mcq:9abd2964', 'economics', 'economics:2-6-production', '2.6 Production', 'mcq', 'mcq', 1, '{"question": "Total cost is £1,000 at an output of 100 units. Average cost is...", "options": ["£10 per unit", "£1,000 per unit", "£1 per unit", "£100 per unit"]}'::jsonb, '{"answer": 0, "explain": "AC = TC ÷ quantity = £1,000 ÷ 100 = £10 per unit. Falling AC means the firm is getting more efficient."}'::jsonb),
('economics:2-6-production:mcq:2116bd67', 'economics', 'economics:2-6-production', '2.6 Production', 'mcq', 'mcq', 1, '{"question": "A café sells 1,000 coffees at £0.80 each. Its costs are £0.15 per coffee plus £75 of fixed costs. Its profit is...", "options": ["£650", "£225", "£575", "£800"]}'::jsonb, '{"answer": 2, "explain": "TR = 1,000 × £0.80 = £800. TC = (1,000 × £0.15) + £75 = £225. Profit = £800 − £225 = £575."}'::jsonb)
